import numpy as np

def _kmeans_inertia(X, K, seed):
    rng = np.random.default_rng(seed)
    N = len(X)
    idx = rng.choice(N, size=K, replace=False)
    centroids = X[idx].copy().astype(np.float64)
    for _ in range(100):
        dists = np.sum((X[:, None, :] - centroids[None, :, :]) ** 2, axis=2)
        labels = np.argmin(dists, axis=1)
        new_centroids = np.array([
            X[labels == k].mean(axis=0) if (labels == k).sum() > 0 else centroids[k]
            for k in range(K)
        ])
        if np.allclose(new_centroids, centroids):
            break
        centroids = new_centroids
    return float(np.sum(np.min(dists, axis=1)))

def compute_inertias(
    X: np.ndarray,
    max_k: int,
    n_init: int = 3,
    seed: int = None
) -> list[float]:
    inertias = []
    rng = np.random.default_rng(seed)
    for k in range(1, max_k + 1):
        best = float('inf')
        for init in range(n_init):
            s = rng.integers(0, 10000)
            val = _kmeans_inertia(X, k, int(s))
            if val < best:
                best = val
        inertias.append(best)
    return inertias

def elbow_k(inertias: list[float]) -> int:
    if len(inertias) <= 2:
        return 1
    diffs = np.diff(inertias)  # first differences
    second_diffs = np.diff(diffs)  # second differences (curvature)
    # Elbow is where second difference is most negative (sharpest bend)
    elbow_idx = int(np.argmax(-second_diffs))  # index in second_diffs
    return elbow_idx + 2  # +1 for 1-indexing, +1 because second_diffs starts at K=2

def silhouette_score(X: np.ndarray, labels: np.ndarray) -> float:
    N = len(X)
    unique_labels = np.unique(labels)
    if len(unique_labels) < 2:
        return 0.0
    dists = np.sqrt(np.sum((X[:, None, :] - X[None, :, :]) ** 2, axis=2))
    scores = []
    for i in range(N):
        same = labels == labels[i]
        same[i] = False
        if same.sum() == 0:
            a = 0.0
        else:
            a = dists[i, same].mean()
        b = float('inf')
        for lbl in unique_labels:
            if lbl == labels[i]:
                continue
            other = labels == lbl
            if other.sum() > 0:
                b = min(b, dists[i, other].mean())
        if b == float('inf'):
            b = 0.0
        denom = max(a, b)
        scores.append((b - a) / denom if denom > 0 else 0.0)
    return float(np.mean(scores))
